#!/usr/bin/env node
/**
 * Guard: the committed `styles.css` must equal a fresh build of `css/input.css`.
 *
 * Every page links the built `styles.css`. The source of truth is `css/main.css`
 * (imported by `css/input.css`); `styles.css` is generated by `npm run css:build`.
 * Two recurring failures ship wrong styles to production with NO error:
 *   1. `styles.css` hand-edited directly (forbidden — see CLAUDE.md / docs/CSS.md).
 *   2. `main.css` changed but `npm run css:build` not re-run before commit.
 * This check rebuilds to a temp file and fails if the result differs from the
 * committed `styles.css`, catching both. It does NOT modify `styles.css`.
 *
 * Fix on failure: `npm run css:build` then commit the updated `styles.css`.
 */
import { spawnSync } from "node:child_process";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), "..");
const input = path.join(root, "css", "input.css");
const committed = path.join(root, "styles.css");
const cli = path.join(root, "node_modules", "@tailwindcss", "cli", "dist", "index.mjs");

if (!fs.existsSync(committed)) {
  console.error("Missing styles.css — run `npm run css:build`.");
  process.exit(1);
}
if (!fs.existsSync(input)) {
  console.error("Missing css/input.css");
  process.exit(1);
}

const tmp = path.join(os.tmpdir(), `tw-styles-check-${process.pid}.css`);
try {
  const result = spawnSync(
    process.execPath,
    [cli, "-i", input, "-o", tmp, "--minify"],
    { cwd: root, stdio: ["ignore", "ignore", "inherit"], env: process.env }
  );
  if (result.status !== 0) {
    console.error("CSS build failed during check.");
    process.exit(result.status ?? 1);
  }

  const fresh = fs.readFileSync(tmp, "utf8");
  const have = fs.readFileSync(committed, "utf8");
  if (fresh !== have) {
    console.error(
      "styles.css is OUT OF SYNC with a fresh build of css/main.css.\n" +
        "Either styles.css was hand-edited, or css:build was not re-run after a CSS change.\n" +
        "Fix: run `npm run css:build` and commit the updated styles.css."
    );
    process.exit(1);
  }
  console.log("OK - styles.css matches a fresh css:build.");
} finally {
  try { fs.rmSync(tmp, { force: true }); } catch { /* ignore */ }
}
